with open('/home/archon/FormalizationProjects/Algebraic-Jacobian-Challenge/AlgebraicJacobian/Picard/TensorObjSubstrate.lean') as f:
    lines = f.readlines()

# Find all /- -/ block comment spans
depth = 0
start = None
spans = []
for i, line in enumerate(lines, 1):
    # Count opening /- and closing -/
    stripped = line
    j = 0
    while j < len(stripped):
        if stripped[j:j+2] == '/-':
            if depth == 0:
                start = i
            depth += 1
            j += 2
        elif stripped[j:j+2] == '-/':
            depth -= 1
            if depth == 0:
                spans.append((start, i, i - start + 1))
            j += 2
        else:
            j += 1

# Show spans > 10 lines
print('Large block comments (>10 lines):')
for s, e, length in spans:
    if length > 10:
        print(f'  L{s}-L{e}: {length} lines')
"
